import{_ as t,H as n,f as s,i as e}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"分布式系统理论系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/00-写作计划.md","filePath":"../distributedLearning/00-写作计划.md","lastUpdated":1778496697000}'),i={name:"../distributedLearning/00-写作计划.md"};function l(o,a,r,d,p,u){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="分布式系统理论系列写作计划" tabindex="-1">分布式系统理论系列写作计划 <a class="header-anchor" href="#分布式系统理论系列写作计划" aria-label="Permalink to &quot;分布式系统理论系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第三类「纵深主题」第七项(G. distributed),⭐⭐⭐⭐。 systemDesign 教了「<strong>怎么搭一个能抗住流量的系统</strong>」(缓存 / 限流 / 多机房 / 容灾),本系列教了「<strong>这些系统底下凭什么能跑对</strong>」——为什么三台机器写同一个值这么难、为什么 2PC 会卡死、为什么 Raft 比 Paxos 火、为什么 Spanner 要装原子钟、为什么 Redlock 被 Martin Kleppmann 喷。 <strong>看完这层,你看任何分布式中间件都能直接看到底</strong>——ZooKeeper / etcd / Kafka / TiDB / Cassandra / Spanner,全是这层往上长出来的。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,从「机器视角的不可能」到「工程上的妥协与组合」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 基础(为什么分布式难 / 八大谬误 / CAP / 一致性 vs 共识)</span></span>
<span class="line"><span>   → 时间与因果(物理时钟 / Lamport / 向量时钟 / HLC / TrueTime)</span></span>
<span class="line"><span>   → 共识与复制(FLP / Paxos / Raft / ZAB / 拜占庭)</span></span>
<span class="line"><span>   → 一致性模型(Linearizability / Sequential / Causal / Eventual / CRDT)</span></span>
<span class="line"><span>   → 分布式事务(2PC / 3PC / Saga / TCC / Percolator / Spanner)</span></span>
<span class="line"><span>   → 工程基石(分布式锁 / 选主 / Gossip / 服务发现 / 脑裂)</span></span></code></pre></div><p><strong>这个系列不是 DDIA 重写</strong>——DDIA 体量大、面向&quot;全栈数据系统&quot;,<strong>本系列偏&quot;理论纵深 + 工程映射&quot;</strong>:每个抽象都讲清楚「为什么需要 → 数学/算法是什么 → 落到哪个工程系统上 → 局限与代价」,看完能直接对着 etcd / TiDB / Kafka 的设计文档&quot;看懂他们在抄哪一篇论文&quot;。</p><p>不展开到证明每一步推导,<strong>而是讲清楚&quot;应用工程师 / 中间件作者需要懂的理论图景&quot;</strong>——你不一定要会重写 Paxos,但选型、排错、容灾设计、面试白板都要懂这些。<strong>95% 的&quot;诡异分布式 bug&quot;最终都落到这一层的某个不变量被破坏。</strong></p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-心智与基础-01-04" tabindex="-1">第一层:心智与基础(01-04) <a class="header-anchor" href="#第一层-心智与基础-01-04" aria-label="Permalink to &quot;第一层:心智与基础(01-04)&quot;">​</a></h3><ul><li>[x] 01 分布式系统总览(为什么需要分布式 / 单机的天花板在哪 / 分布式的真实代价)</li><li>[x] 02 八大谬误与故障模型(网络可靠 / 延迟为零 / 拓扑不变 / 崩溃 vs 拜占庭 vs 遗漏)</li><li>[x] 03 一致性、共识、一致性模型(三个最容易混的术语,讲清楚再读论文)</li><li>[x] 04 CAP / PACELC / BASE(为什么 CAP 不是非黑即白 / 延迟也要算进来 / BASE 怎么落地)</li></ul><h3 id="第二层-时间与因果-05-08" tabindex="-1">第二层:时间与因果(05-08) <a class="header-anchor" href="#第二层-时间与因果-05-08" aria-label="Permalink to &quot;第二层:时间与因果(05-08)&quot;">​</a></h3><ul><li>[x] 05 物理时钟为什么不靠谱(NTP / 时钟漂移 / 闰秒 / 时间倒流引发的真实事故)</li><li>[x] 06 Lamport 逻辑时钟与全序(happens-before / 偏序如何打成全序 / 工程怎么用)</li><li>[x] 07 向量时钟与版本向量(因果追踪 / Dynamo / Riak / 冲突检测的代价)</li><li>[x] 08 HLC 与 TrueTime(混合逻辑时钟 / Spanner 的原子钟工程 / CockroachDB 怎么模仿)</li></ul><h3 id="第三层-共识与复制-09-15" tabindex="-1">第三层:共识与复制(09-15) <a class="header-anchor" href="#第三层-共识与复制-09-15" aria-label="Permalink to &quot;第三层:共识与复制(09-15)&quot;">​</a></h3><ul><li>[x] 09 FLP 不可能定理(异步 + 一个故障 = 共识不可能 / 工程上怎么绕过它)</li><li>[x] 10 复制三态(主从 / 多主 / 无主 / Quorum NWR / 同步 vs 异步 vs 半同步)</li><li>[x] 11 Paxos 经典版(Basic Paxos / Proposer / Acceptor / Learner / 为什么这么难懂)</li><li>[x] 12 Multi-Paxos 与工程化(Leader / 日志复制 / Chubby / Spanner 真正在用的版本)</li><li>[x] 13 Raft 全解(选主 / 日志复制 / 安全性 / 成员变更 / 为什么它取代了 Paxos)</li><li>[x] 14 ZAB 与 EPaxos(ZooKeeper 内部 / 无 Leader 的 Paxos 变体 / 谁更适合什么场景)</li><li>[x] 15 拜占庭容错(PBFT / Tendermint / 区块链共识 / 为什么 N≥3f+1)</li></ul><h3 id="第四层-一致性模型-16-19" tabindex="-1">第四层:一致性模型(16-19) <a class="header-anchor" href="#第四层-一致性模型-16-19" aria-label="Permalink to &quot;第四层:一致性模型(16-19)&quot;">​</a></h3><ul><li>[x] 16 一致性模型谱(Linearizability / Sequential / Causal / Read-Your-Writes / Eventual)</li><li>[x] 17 Linearizability 深入(可线性化 = 看起来像单机 / CAS 的诱惑 / 测试用 Jepsen)</li><li>[x] 18 因果一致性(因果是 CAP 之外的甜点 / COPS / Bolt-on Causal / 协同编辑里的实践)</li><li>[x] 19 CRDT(无冲突复制数据类型 / G-Counter / OR-Set / Yjs / Automerge / Figma 同步)</li></ul><h3 id="第五层-分布式事务-20-24" tabindex="-1">第五层:分布式事务(20-24) <a class="header-anchor" href="#第五层-分布式事务-20-24" aria-label="Permalink to &quot;第五层:分布式事务(20-24)&quot;">​</a></h3><ul><li>[x] 20 ACID 在分布式下的崩塌(单机 ACID 怎么获得 / 跨机后每个字母都会破)</li><li>[x] 21 2PC 与 3PC(两阶段提交 / 协调者宕机 / 3PC 解决了什么又留下什么)</li><li>[x] 22 Saga 与 TCC(长事务 / 补偿模型 / 业务幂等 / 怎么和消息队列组合)</li><li>[x] 23 Percolator(Google 的分布式事务 / 快照隔离 / TiKV / 主键锁与冲突解决)</li><li>[x] 24 Spanner / Calvin / NewSQL(TrueTime + Paxos / 外部一致性 / 确定性事务流派)</li></ul><h3 id="第六层-工程基石-25-30" tabindex="-1">第六层:工程基石(25-30) <a class="header-anchor" href="#第六层-工程基石-25-30" aria-label="Permalink to &quot;第六层:工程基石(25-30)&quot;">​</a></h3><ul><li>[x] 25 一致性哈希再深入(虚拟节点 / Jump Hash / Maglev / Rendezvous / 各自的场景)</li><li>[x] 26 分布式锁(Redlock 争议 / ZK 锁 / etcd 锁 / Fencing Token / 锁的两个用途)</li><li>[x] 27 选主与租约(Lease / 心跳超时 / GFS Master / 怎么避免双主)</li><li>[x] 28 Gossip 协议(SWIM / 反熵 / Cassandra / Consul / Serf 的成员管理)</li><li>[x] 29 服务发现与配置中心(ZK / etcd / Consul / Nacos 对比 / 强一致 vs AP 的选型)</li><li>[x] 30 故障检测与脑裂(φ-accrual / Quorum 防脑裂 / Fencing / STONITH / 网络分区下的纪律)</li></ul><hr><h2 id="关键论文与系统索引" tabindex="-1">关键论文与系统索引 <a class="header-anchor" href="#关键论文与系统索引" aria-label="Permalink to &quot;关键论文与系统索引&quot;">​</a></h2><p>每层引用的&quot;地标论文 / 工程系统&quot;,写作时按这个清单倒着核对篇章是否漏点:</p><table tabindex="0"><thead><tr><th>层</th><th>关键论文</th><th>落到哪个系统</th></tr></thead><tbody><tr><td>心智</td><td><em>Fallacies of Distributed Computing</em>(Deutsch &amp; Gosling) / Brewer CAP</td><td>—</td></tr><tr><td>时间</td><td>Lamport <em>Time, Clocks…</em>(1978) / Mattern <em>Vector Clocks</em> / CockroachDB HLC / Spanner TrueTime</td><td>DynamoDB / CockroachDB / Spanner</td></tr><tr><td>共识</td><td>FLP(1985) / Paxos Made Simple / Raft(2014) / ZAB / EPaxos / PBFT</td><td>Chubby / etcd / Consul / ZooKeeper / 区块链</td></tr><tr><td>一致性模型</td><td>Herlihy &amp; Wing <em>Linearizability</em> / Lamport <em>Sequential Consistency</em> / Bailis <em>Bolt-on Causal</em> / Shapiro <em>CRDT</em></td><td>DynamoDB / Riak / Yjs / Figma</td></tr><tr><td>事务</td><td>Gray <em>2PC</em> / Garcia-Molina <em>Saga</em>(1987) / Percolator(2010) / Spanner(2012) / Calvin(2012)</td><td>TiDB / CockroachDB / Spanner / FaunaDB</td></tr><tr><td>工程基石</td><td>Karger <em>Consistent Hashing</em> / Maglev(2016) / SWIM(2002) / Chubby Lease / Jepsen 报告系列</td><td>Cassandra / Consul / Serf / etcd / Redlock</td></tr></tbody></table><hr><h2 id="读者画像" tabindex="-1">读者画像 <a class="header-anchor" href="#读者画像" aria-label="Permalink to &quot;读者画像&quot;">​</a></h2><p>本系列假设读者已具备:</p><ul><li>写过至少一年后端代码、用过至少一个分布式中间件(Redis / Kafka / MySQL 主从 / ZK / etcd 任一)</li><li>看过 systemDesign 第 04 篇(CAP 与一致性谱)或等价材料,知道一致性&quot;有强弱之分&quot;但说不清楚</li><li>不要求会读 TLA+,但要求&quot;看到伪代码 + 状态机能跟下来&quot;</li></ul><p>如果你完全没碰过 Redis 主从延迟、MySQL 半同步、Kafka ISR 这些工程现象,建议先把 systemDesign / backendLearning 过一遍,再来这层补&quot;为什么&quot;。</p><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>心智 / CAP / 抗压基础设施</td><td>systemDesign/01-13 ✅</td><td>不重复,本系列只补&quot;为什么 CAP 是这样&quot;的理论纵深(04)</td></tr><tr><td>一致性哈希(实现层)</td><td>algorithmLearning/25 ✅</td><td>不重复,本系列讲算法变体与选型(25)</td></tr><tr><td>微服务 / 服务治理 / 注册中心</td><td>backendLearning ✅</td><td>不重复,本系列讲注册中心<strong>底下的共识与一致性模型</strong>(29)</td></tr><tr><td>经典案例(IM / Feed / 秒杀)</td><td>systemDesign/16-24 ✅</td><td>不重复,本系列不写业务系统</td></tr><tr><td>多机房 / 异地多活 / 容灾</td><td>systemDesign/25-26 ✅</td><td>互补,本系列讲多机房<strong>底下的复制与时钟</strong>(05-15)</td></tr><tr><td>消息队列与事件驱动</td><td>systemDesign/10 ✅</td><td>不重复,只在 Saga(22)讲它和事务的组合</td></tr><tr><td>网络协议栈 / TCP / TLS</td><td>networkLearning ✅</td><td>不重复,只在故障检测(30)讲网络分区表现</td></tr><tr><td>单机锁 / 内存模型</td><td>osLearning/14-15 ✅</td><td>不重复,本系列只讲<strong>跨机</strong>锁</td></tr><tr><td>数据库 GC / 存储引擎</td><td>(未来 dbLearning)</td><td>不交叉,本系列不深入存储引擎</td></tr><tr><td>区块链协议细节</td><td>(不写)</td><td>拜占庭只到 PBFT/Tendermint 的算法层(15)</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;为什么 → 是什么 → 工程对应 → 局限&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 为什么需要这个东西</span></span>
<span class="line"><span>   - 不要它的世界长什么样(具体故障 / 不变量被破坏的例子)</span></span>
<span class="line"><span>   - 加了它解决了什么、付出了什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 它到底是什么</span></span>
<span class="line"><span>   - 关键不变量(invariant)</span></span>
<span class="line"><span>   - 算法关键步骤 / 状态机</span></span>
<span class="line"><span>   - 一张时序图或状态图</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工程上谁在用</span></span>
<span class="line"><span>   - 对应到一个真实系统(etcd / TiDB / Cassandra / Spanner / Kafka …)</span></span>
<span class="line"><span>   - 该系统在原理基础上做了哪些工程妥协</span></span>
<span class="line"><span>   - 配置参数怎么对应到理论变量</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 局限与代价</span></span>
<span class="line"><span>   - 这个方案不能做什么</span></span>
<span class="line"><span>   - 真实事故案例(Jepsen 报告 / 公司 post-mortem)</span></span>
<span class="line"><span>   - 何时该换方案</span></span></code></pre></div><p>不堆论文证明——<strong>只贴关键不变量、伪代码和时序图</strong>,让读者「看到这一层在保护什么、被什么打破」就够了。</p><p>每篇遇到协议、状态机、消息时序,<strong>一定画图</strong>——Paxos / Raft / 2PC / Gossip 没图等于没写。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-04  心智:看完知道&quot;分布式贵在哪 / 为什么很多需求不该上分布式&quot;</span></span>
<span class="line"><span>05-08  时间:看完不会再写&quot;用本地时间戳做全局顺序&quot;</span></span>
<span class="line"><span>09-15  共识:**最值钱的一层**,Paxos / Raft / ZAB 是所有协调服务的底</span></span>
<span class="line"><span>16-19  一致性模型:**最容易被忽略**,大多数&quot;诡异 bug&quot;是模型选错</span></span>
<span class="line"><span>20-24  事务:**面试和真实工作的硬通货**,从 2PC 一路到 Spanner</span></span>
<span class="line"><span>25-30  工程基石:每个中间件都在用的零件,选型必懂</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 09-15 + 16-19 + 20-24 这 16 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 Raft 比 Paxos 火,但 Paxos 不会被淘汰&quot;</li><li>&quot;为什么 Redlock 不安全,Martin Kleppmann 的那篇喷文到底在喷什么&quot;</li><li>&quot;Spanner 为什么要装原子钟,装不起原子钟的人怎么用 HLC 模仿&quot;</li><li>&quot;为什么 Saga 不是 2PC 的替代品,它换走了什么&quot;</li><li>&quot;为什么 ZK 是 CP 但 Eureka 选 AP,业务场景该怎么对应&quot;</li></ul><p>能讲清楚一题这个系列就值了。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li>「Paxos 论文逐句翻译 / Raft 论文翻译」——不是论文导读,是工程师视角</li><li>「先讲个 Google / Amazon 大故事」——直接进重点,案例只在「工程对应」一段引用</li><li>抄 DDIA / 抄分布式课件——那些资料都在,这里只补它们没串起来的&quot;为什么 + 工程映射&quot;</li><li>「这是面试常考」——读者来这里是为了真懂,不是背 CAP 三选二</li><li>不画图就讲 Paxos / Raft / 2PC / Gossip / 向量时钟——这些<strong>不画图永远讲不清楚</strong></li><li>写业务系统设计(IM / 订单)——那是 systemDesign 的活</li><li>深入到存储引擎 LSM / B+ Tree / WAL 细节——留给未来的 dbLearning,本系列只到&quot;复制 / 事务 / 共识&quot;</li><li>区块链经济学 / 代币 / Layer2 ——拜占庭只到协议层(PBFT / Tendermint),不碰公链生态</li></ol><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>本系列<strong>只服务于&quot;理解 + 选型 + 排错&quot;</strong>——不是教你重写一个 Raft 库,而是教你看懂你正在用的那个 Raft 库为什么这么写、什么时候会坏、坏了往哪里查。</p><p>所有算法描述限制在伪代码与时序图层面,<strong>不提供生产级实现</strong>;所有工程映射都指向公开论文、开源系统或公司公开 post-mortem,不引用任何未公开的内部资料。</p><hr><h2 id="读完之后去哪" tabindex="-1">读完之后去哪 <a class="header-anchor" href="#读完之后去哪" aria-label="Permalink to &quot;读完之后去哪&quot;">​</a></h2><ul><li>想动手:挑一个开源 Raft 库(hashicorp/raft / dragonboat / braft)读一遍,对照第 13 篇核对每个不变量</li><li>想做混沌:跟一遍 Jepsen 公开报告(etcd / TiDB / MongoDB),对照第 17 / 21 / 23 篇看故障如何打破不变量</li><li>想再深:读 <em>Designing Data-Intensive Applications</em>(DDIA)第 II 部 + Lamport 选集 + Spanner / Calvin 原论文</li><li>想再宽:等未来的 <strong>dbLearning</strong>(存储引擎 / LSM / WAL)和已有的 systemDesign 多机房章节,一上一下夹住这一层</li></ul>`,57)])])}const g=t(i,[["render",l]]);export{c as __pageData,g as default};
